# If the default icon name is being returned (based on what user has selected), then
# change the font color of icon name such that it is darker (like a placeholder).

if len(value) == 0:
	return '--neutral-60'
else:
	return '--neutral-100'

# If the user has not selected an icon manually, then we can use the current
# params, ac, name, tag path, and type, to figure out a default icon and then
# return the name of it.

typeMap = {'fan':'Fan','condenser':'Condenser','economizer':'Economizer','heatingControls':'Heating Controls','compressor':'Compressor','':''}

icon = value['icon']
type = value['type']
ac = value['ac']
path = value['path']
name = value['name']

if len(icon) == 0:
	if ac == -1:
		return ''
	elif ac in [1,2] and type != 'other':
		return typeMap[type]
	elif ac in [1,2] and type == 'other':
		if 'pressure' in name.lower():
			return 'Pressure'
		elif 'smoke' in name.lower():
			return 'smoke free'
		elif 'temp' in name.lower() or 'differential' in name.lower():
			return 'Temperature'
		elif 'cold' in name.lower():
			return 'ac unit'
		elif 'hot' in name.lower():
			return 'whatshot'
		else:
			return 'info'
	elif ac == 3:
		if 'cooling' in name.lower() or 'peak' in name.lower():
			return 'ac unit'
		elif 'heating' in name.lower():
			return 'whatshot'
		elif 'temp' in name.lower():
			return 'Temperature'
		else:
			return 'info'
else:
	return icon.replace('_',' ')

if value == 'condenser':
	return 'var(--neutral-100)'
else:
	return 'var(--neutral-60)'

# If the user has manually configured an icon and it is not one of the
# built-in icons, then display this icon component.

if len(value) > 0 and value not in ['heating_controls','fan','condenser','economizer','compressor','temperature','pressure']:
	return True
else:
	return False

# If the user has not manually configured an icon and one of the
# built-in icons is not visible, then this 'fallback' icon will
# be displayed.

icon = value['icon']

if len(icon) > 0:
	return False
else:
	ac = value['ac']
	type = value['type']
	name = value['name']

	if ac == -1:
		return False
	elif ac in [1,2] and type != 'other':
		return False
	elif ac in [1,2] and type == 'other':
		if 'pressure' in name.lower() or 'temp' in name.lower() or 'differential' in name.lower():
			return False
		else:
			return True
	elif ac == 3:
		if 'temp' in name.lower():
			return False
		else:
			return True

# If the user has not manually configured an icon, then this displays
# a 'fallback' icon (the icon displayed depends on the values of the
# params).

icon = value['icon']

if len(icon) > 0:
	return 'material/info'
else:
	ac = value['ac']
	type = value['type']
	name = value['name']

	if ac == -1:
		return 'material/info'
	elif ac in [1,2] and type != 'other':
		return 'material/info'
	elif ac in [1,2] and type == 'other':
		if 'smoke' in name.lower():
			return 'material/smoke_free'
		elif 'cold' in name.lower():
			return 'material/ac_unit'
		elif 'hot' in name.lower():
			return 'material/whatshot'
		else:
			return 'material/info'
	elif ac == 3:
		if 'cooling' in name.lower() or 'peak' in name.lower():
			return 'material/ac_unit'
		elif 'heating' in name.lower():
			return 'material/whatshot'
		else:
			return 'material/info'

if value == 'compressor':
	return 'var(--neutral-100)'
else:
	return 'var(--neutral-60)'

if value == 'fan':
	return 'var(--neutral-100)'
else:
	return 'var(--neutral-60)'

if value == 'heating_controls':
	return 'var(--neutral-100)'
else:
	return 'var(--neutral-60)'

if value == 'economizer':
	return 'var(--neutral-100)'
else:
	return 'var(--neutral-60)'

# If the user selected the 'temperature' icon, or if the user
# did not manually configure an icon and 'temp' or 'differential'
# is in the name of the tag, then display the 'temperature' icon.

icon = value['icon']

if icon == 'temperature':
	return True
elif len(icon) > 0:
	return False
else:
	ac = value['ac']
	type = value['type']
	name = value['name']

	if ac in [1,2] and type == 'other':
		if 'temp' in name.lower() or 'differential' in name.lower():
			return True
		else:
			return False
	elif ac == 3:
		if 'temp' in name.lower():
			return True
		else:
			return False
	else:
		return False

if value == 'temperature':
	return 'var(--neutral-100)'
else:
	return 'var(--neutral-60)'

# If the user selected the 'pressure' icon, or if the user
# did not manually configure an icon and 'pressure' is in
# the name of the tag, then display the 'pressure' icon.	

icon = value['icon']

if icon == 'pressure':
	return True
elif len(icon) > 0:
	return False
else:
	ac = value['ac']
	type = value['type']
	name = value['name']

	if ac in [1,2] and type == 'other':
		if 'pressure' in name.lower():
			return True
		else:
			return False
	else:
		return False

if value == 'pressure':
	return 'var(--neutral-100)'
else:
	return 'var(--neutral-60)'

